export interface ImageInfo {
  width: number;
  height: number;
  bitsPerSample: 8 | 16 | 32;
  hasAlpha: boolean;
  hasAnimation: boolean;
  iccProfile?: Uint8Array;          // present when the file carries one
  colorSpace?: ColorSpaceHint;
  exif?: Uint8Array;                // raw EXIF box
  xmp?: Uint8Array;                 // raw XMP box
  jpegReconstructionAvailable: boolean;
}

export interface MsgDecodeProgress extends DecodeFrameMeta {
  type: "decode_progress";
  sessionId: string;
  stage: DecodeStage;
  info: ImageInfo;      // full copy including iccProfile/exif/xmp blobs on every pass
  pixels: ArrayBuffer;  // transferred
  format: PixelFormat;
  pixelStride: number;
  copyMs?: number;
  copiedBytes?: number;
  timeToFirstPixelMs?: number;
}
